import {{ Injectable }} from '@nestjs/common';
import {{ LoggingService }} from './models/logging.model';
import {{ LoggingServiceRepository }} from './repositories/logging.repository';

@Injectable()
export class LoggingServiceService {{
  constructor(
    private readonly repository: LoggingServiceRepository,
  ) {{}}

  async findAll(): Promise<LoggingService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<LoggingService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<LoggingService>): Promise<LoggingService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<LoggingService>): Promise<LoggingService> {{
    return this.repository.update(id, data);
  }}
}}
